import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';
import { remark } from 'remark';
import html from 'remark-html';



export default async function LogEntry({ 
  params 
}: { 
  params: Promise<{ slug: string }> // 1. Update type to Promise
}) {
    // 2. We MUST await the params before accessing the slug
    const { slug } = await params;

    // 3. Now slug is "2026-03-16-migration-to-nextjs" instead of undefined
    const fullPath = path.join(process.cwd(), 'content/logs', `${slug}.md`);

    // Read the file contents
    const fileContents = fs.readFileSync(fullPath, 'utf8');

    // Use gray-matter to pull out the metadata and content
    const { data, content } = matter(fileContents);

    // Use remark to convert Markdown to HTML
    const processedContent = await remark().use(html).process(content);
    const contentHtml = processedContent.toString();

    return (
        <article className="max-w-2xl mx-auto py-20 px-6">
            <header className="mb-8 font-bold dark:bg-gray-400 p-5 rounded-2xl">
                <h1 className="text-4xl font-extrabold text-slate-900">{data.title}</h1>
                <p className=" text-black mt-2">{data.date}</p>

            </header>
            
            <div
                className='prose prose-slate lg:prose-xl max-w-none prose-headings:font-bold prose-headings:text-slate-900 prose-h1:text-5xl prose-h2:text-3xl'
                dangerouslySetInnerHTML={{ __html: contentHtml }}
            />
        </article>
    );
}

export async function generateStaticParams() {
    const files = fs.readdirSync(path.join(process.cwd(), 'content/logs'));

    return files.map((filename) => ({
        slug: filename.replace('.md', ''),
    }));
}




